const { Storage } = require('@google-cloud/storage');
const storage = new Storage();

/**
 * Node.js Cloud Function that serves files from Cloud Storage based on HTTP request path parameter.
 * It accepts 'bucket' and 'filePath' from the query string and streams the file.
 * Supports nested paths for filePath.
 *
 * @param {object} req The HTTP request object.
 * @param {object} res The HTTP response object.
 */
exports.serveCloudStorageFile = async (req, res) => {
  const { bucket, filePath } = req.query;

  // Validate that 'bucket' and 'filePath' query parameters are provided.
  if (!bucket || !filePath) {
    res.status(400).send('Bad Request: "bucket" and "filePath" query parameters are required.');
    return;
  }

  // Get a reference to the file in Cloud Storage. The filePath inherently supports nested paths.
  const file = storage.bucket(bucket).file(filePath);

  try {
    // Retrieve file metadata to check for existence and determine content type.
    const [metadata] = await file.getMetadata();

    // Set appropriate HTTP headers for the response.
    // Content-Type is retrieved from the file's metadata, defaulting to application/octet-stream if not set.
    res.set('Content-Type', metadata.contentType || 'application/octet-stream');
    // Set Cache-Control header to allow browser caching for a reasonable duration (e.g., 1 hour).
    res.set('Cache-Control', 'public, max-age=3600'); // Cache for 1 hour

    // Create a readable stream from the Cloud Storage file.
    const readStream = file.createReadStream();

    // Handle errors during the streaming process.
    readStream.on('error', (err) => {
      console.error(`Error streaming file "${filePath}" from bucket "${bucket}":`, err);
      // Only send an error response if headers haven't already been sent.
      if (!res.headersSent) {
        res.status(500).send('Internal Server Error: Could not stream file.');
      }
      // Destroy the stream to prevent resource leaks.
      readStream.destroy();
    });

    // Pipe the file stream directly to the HTTP response.
    readStream.pipe(res);

  } catch (err) {
    console.error(`Error serving file "${filePath}" from bucket "${bucket}":`, err);

    // Handle specific error codes from Cloud Storage.
    if (err.code === 404) {
      res.status(404).send(`Not Found: File "${filePath}" not found in bucket "${bucket}".`);
    } else {
      // For any other errors (e.g., permissions, bucket not found), send a 500 Internal Server Error.
      res.status(500).send('Internal Server Error: Could not retrieve file.');
    }
  }
};